interface User { id: number; username: string }
interface Post { id: number; userId: number; title: string }

function combineData(users: User[], posts: Post[]): any[] {
  return posts
    .filter(p => p.title.startsWith("Release"))
    .map(p => {
      const match = users.find(u => u.id === p.userId);
      return { title: p.title, username: match?.username };
    });
}

interface Transaction { category: string; value: number }

function computeTotals(txs: Transaction[]): Record<string, number> {
  return txs.reduce((acc, curr) => {
    acc[curr.category] = (acc[curr.category] || 0) + curr.value;
    return acc;
  }, {} as Record<string, number>);
}

examples.toCode:
SELECT category, SUM(value) AS total_value
FROM transactions
GROUP BY category;
